mapper.select:

where doctor_id = #{doctorId}
  and schedule_date = #{scheduleDate}
  and time_slot = #{timeSlot}
limit 1

mapper.update:
update schedule
doctor_id = #{doctorId}, schedule_date = #{scheduleDate}, time_slot = #{timeSlot}, max_number = #{maxNumber}, reserved_number = #{reservedNumber}, status = #{status}, create_time = #{createTime}, update_time = #{updateTime},
where schedule_id = #{scheduleId}

update schedule set reserved_number = reserved_number - 1, update_time = now()
where schedule_id = #{scheduleId}
  and reserved_number > 0
